def check_alert_condition(current_value, threshold, operator):
    if operator == ">":
        return current_value > threshold
    elif operator == ">=":
        return current_value >= threshold
    elif operator == "<":
        return current_value < threshold
    elif operator == "<=":
        return current_value <= threshold
    elif operator == "==":
        return current_value == threshold
    elif operator == "!=":
        return current_value != threshold
    else:
        raise ValueError(f"Invalid operator: {operator}")
